import java.io.IOException;

/**
 * Service for securely validating and loading XML configurations.
 */
public class ConfigService {

    /**
     * Validates an XML file for well-formedness and parses it into a DOM Document.
     * Includes comprehensive safeguards against XML External Entity (XXE) injection attacks.
     *
     * @param configPath The path to the user-provided XML configuration file.
     * @return The parsed org.w3c.dom.Document object.
     * @throws IllegalArgumentException     If the path is null, empty, or the file does not exist.
     * @throws SAXException                 If the XML validation fails or parsing fails (malformed XML).
     * @throws IOException                  If an I/O error occurs while reading the file.
     * @throws ParserConfigurationException If a DocumentBuilder cannot be created with the requested configuration.
     */
    public Document loadConfig(String configPath) throws SAXException, IOException, ParserConfigurationException {
        // 1. Input Validation
        if (configPath == null || configPath.trim().isEmpty()) {
            throw new IllegalArgumentException("Configuration path cannot be null or empty.");
        }

        File configFile = new File(configPath);
        if (!configFile.exists() || !configFile.isFile()) {
            throw new IllegalArgumentException("Configuration file not found or is not a valid file: " + configPath);
        }

        // 2. XML Validation Phase (Checking for well-formedness)
        // Using W3C XML Schema namespace to instantiate the factory
        SchemaFactory schemaFactory = SchemaFactory.newInstance(XMLConstants.W3C_XML_SCHEMA_NS_URI);

        // Secure the SchemaFactory against XXE vulnerabilities
        schemaFactory.setProperty(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        schemaFactory.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

        // Calling newSchema() without arguments creates a schema that simply checks for well-formedness
        Schema schema = schemaFactory.newSchema();
        Validator validator = schema.newValidator();

        // Secure the Validator against XXE vulnerabilities
        validator.setProperty(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        validator.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

        // Perform validation. Throws SAXException if the XML is malformed.
        validator.validate(new StreamSource(configFile));

        // 3. XML Parsing Phase
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();

        // Secure DocumentBuilderFactory against XXE and Billion Laughs attacks
        dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        // Completely disable DOCTYPE declaration to prevent majority of XXE attacks
        dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        // Disable external general entities
        dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
        // Disable external parameter entities
        dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        // Disable external DTDs
        dbf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        dbf.setXIncludeAware(false);
        dbf.setExpandEntityReferences(false);

        // Parse and return the Document
        DocumentBuilder documentBuilder = dbf.newDocumentBuilder();
        return documentBuilder.parse(configFile);
    }
}
